window.exeSearchData = {"SP00000001":{"name":"Inicio","isIndex":true,"fileName":"index.html","fileUrl":"index.html","prePageId":null,"nextPageId":"SP00000008","blocks":{"SP00000002":{"name":"Herramientas de desarrollo, CI e IA","order":1,"idevices":{"SP00000003":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p><strong>Mi caja de herramientas real, no teoría.</strong></p>\n<p>Charla para <strong>3ipunt</strong> — lo que uso a diario para trabajar mejor: shell y utilidades, IA (MCP, skills, ADRs) e integración continua con Make y GitHub Actions.</p>\n<ul>\n<li><strong>Ernesto Serrano</strong> — freelance software / DevOps (ernesto.es). PHP / Moodle, Docker, CI/CD, infra reproducible.</li>\n<li>Cada herramienta que enseño la uso <strong>de verdad</strong>. Iré enseñando el terminal y los repos por el camino.</li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000003\",\"markdownTextarea\":\"**Mi caja de herramientas real, no teoría.**\\n\\nCharla para **3ipunt** — lo que uso a diario para trabajar mejor: shell y utilidades, IA (MCP, skills, ADRs) e integración continua con Make y GitHub Actions.\\n\\n- **Ernesto Serrano** — freelance software / DevOps (ernesto.es). PHP / Moodle, Docker, CI/CD, infra reproducible.\\n- Cada herramienta que enseño la uso **de verdad**. Iré enseñando el terminal y los repos por el camino.\",\"markdownTextareaHtml\":\"<p><strong>Mi caja de herramientas real, no teoría.</strong></p>\\n<p>Charla para <strong>3ipunt</strong> — lo que uso a diario para trabajar mejor: shell y utilidades, IA (MCP, skills, ADRs) e integración continua con Make y GitHub Actions.</p>\\n<ul>\\n<li><strong>Ernesto Serrano</strong> — freelance software / DevOps (ernesto.es). PHP / Moodle, Docker, CI/CD, infra reproducible.</li>\\n<li>Cada herramienta que enseño la uso <strong>de verdad</strong>. Iré enseñando el terminal y los repos por el camino.</li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000004":{"name":"Agenda: tres bloques","order":2,"idevices":{"SP00000005":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><ol>\n<li><strong>Herramientas</strong> — terminal, mis scripts, gestores de paquetes y utilidades del día a día.</li>\n<li><strong>IA</strong> — cómo doy herramientas (MCP) y contexto (skills, instrucciones, ADRs) a la IA.</li>\n<li><strong>CI</strong> — Make como interfaz única, entornos reproducibles y GitHub Actions.</li>\n</ol>\n<blockquote>\n<p>El hilo de todo: <strong>automatizar el feedback</strong>. Lo que automatizas no se te olvida ni te lo saltas con prisas.</p>\n</blockquote></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000005\",\"markdownTextarea\":\"1. **Herramientas** — terminal, mis scripts, gestores de paquetes y utilidades del día a día.\\n2. **IA** — cómo doy herramientas (MCP) y contexto (skills, instrucciones, ADRs) a la IA.\\n3. **CI** — Make como interfaz única, entornos reproducibles y GitHub Actions.\\n\\n> El hilo de todo: **automatizar el feedback**. Lo que automatizas no se te olvida ni te lo saltas con prisas.\",\"markdownTextareaHtml\":\"<ol>\\n<li><strong>Herramientas</strong> — terminal, mis scripts, gestores de paquetes y utilidades del día a día.</li>\\n<li><strong>IA</strong> — cómo doy herramientas (MCP) y contexto (skills, instrucciones, ADRs) a la IA.</li>\\n<li><strong>CI</strong> — Make como interfaz única, entornos reproducibles y GitHub Actions.</li>\\n</ol>\\n<blockquote>\\n<p>El hilo de todo: <strong>automatizar el feedback</strong>. Lo que automatizas no se te olvida ni te lo saltas con prisas.</p>\\n</blockquote>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000006":{"name":"Notas del ponente","order":3,"idevices":{"SP00000007":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p><strong>Duración total: ~60 min</strong> + preguntas. Reparto aproximado: Herramientas 18' · IA 22' · CI 18' · cierre 2'.</p>\n<p><strong>Tono:</strong> práctico y honesto, <strong>sin hype de IA</strong>. Audiencia técnica de 3ipunt (PHP/Moodle, e-learning, DevOps): no explicar lo básico, conectar con su realidad.</p>\n<p><strong>Formato demo:</strong> cuando puedas, cambia a la terminal o al navegador y <strong>enséñalo funcionando</strong> en vez de leer la diapo. La presentación es el guion; la demo es el mensaje.</p>\n<p>Si te quedas sin tiempo: comprime la sección de utilidades y acorta el ejemplo de mod_exelearning a la diapositiva del ADR.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000007\",\"markdownTextarea\":\"**Duración total: ~60 min** + preguntas. Reparto aproximado: Herramientas 18' · IA 22' · CI 18' · cierre 2'.\\n\\n**Tono:** práctico y honesto, **sin hype de IA**. Audiencia técnica de 3ipunt (PHP/Moodle, e-learning, DevOps): no explicar lo básico, conectar con su realidad.\\n\\n**Formato demo:** cuando puedas, cambia a la terminal o al navegador y **enséñalo funcionando** en vez de leer la diapo. La presentación es el guion; la demo es el mensaje.\\n\\nSi te quedas sin tiempo: comprime la sección de utilidades y acorta el ejemplo de mod_exelearning a la diapositiva del ADR.\",\"markdownTextareaHtml\":\"<p><strong>Duración total: ~60 min</strong> + preguntas. Reparto aproximado: Herramientas 18' · IA 22' · CI 18' · cierre 2'.</p>\\n<p><strong>Tono:</strong> práctico y honesto, <strong>sin hype de IA</strong>. Audiencia técnica de 3ipunt (PHP/Moodle, e-learning, DevOps): no explicar lo básico, conectar con su realidad.</p>\\n<p><strong>Formato demo:</strong> cuando puedas, cambia a la terminal o al navegador y <strong>enséñalo funcionando</strong> en vez de leer la diapo. La presentación es el guion; la demo es el mensaje.</p>\\n<p>Si te quedas sin tiempo: comprime la sección de utilidades y acorta el ejemplo de mod_exelearning a la diapositiva del ADR.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000008":{"name":"Terminal y shell","isIndex":false,"fileName":"terminal-y-shell.html","fileUrl":"html/terminal-y-shell.html","prePageId":"SP00000001","nextPageId":"SP00000015","blocks":{"SP00000009":{"name":"oh-my-zsh + zsh-autosuggestions","order":1,"idevices":{"SP00000010":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>El terminal es donde paso el día: invierte en él.</p>\n<ul>\n<li><strong>oh-my-zsh</strong> — framework para zsh: temas, plugins y atajos con cero esfuerzo. Tema <code>robbyrussell</code>, plugins <code>git</code>, <code>docker</code>, <code>macos</code>, <code>bun</code>.</li>\n<li><strong>zsh-autosuggestions</strong> — sugiere el comando <strong>según tu historial</strong> mientras escribes; aceptas con <code>→</code>. Escribes la mitad y ejecutas lo de siempre.</li>\n<li>El plugin <code>git</code> añade decenas de alias (<code>gst</code>, <code>gco</code>, <code>gp</code>…) y el estado de la rama en el prompt.</li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000010\",\"markdownTextarea\":\"El terminal es donde paso el día: invierte en él.\\n\\n- **oh-my-zsh** — framework para zsh: temas, plugins y atajos con cero esfuerzo. Tema `robbyrussell`, plugins `git`, `docker`, `macos`, `bun`.\\n- **zsh-autosuggestions** — sugiere el comando **según tu historial** mientras escribes; aceptas con `→`. Escribes la mitad y ejecutas lo de siempre.\\n- El plugin `git` añade decenas de alias (`gst`, `gco`, `gp`…) y el estado de la rama en el prompt.\",\"markdownTextareaHtml\":\"<p>El terminal es donde paso el día: invierte en él.</p>\\n<ul>\\n<li><strong>oh-my-zsh</strong> — framework para zsh: temas, plugins y atajos con cero esfuerzo. Tema <code>robbyrussell</code>, plugins <code>git</code>, <code>docker</code>, <code>macos</code>, <code>bun</code>.</li>\\n<li><strong>zsh-autosuggestions</strong> — sugiere el comando <strong>según tu historial</strong> mientras escribes; aceptas con <code>→</code>. Escribes la mitad y ejecutas lo de siempre.</li>\\n<li>El plugin <code>git</code> añade decenas de alias (<code>gst</code>, <code>gco</code>, <code>gp</code>…) y el estado de la rama en el prompt.</li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000011":{"name":"Instalación mínima","order":2,"idevices":{"SP00000012":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><pre><code class=\"language-bash\"># oh-my-zsh\nsh -c \"$(curl -fsSL https://install.ohmyz.sh)\"\n# zsh-autosuggestions (plugin custom) + activarlo en ~/.zshrc\ngit clone https://github.com/zsh-users/zsh-autosuggestions \\\n  ${ZSH_CUSTOM:-~/.oh-my-zsh/custom}/plugins/zsh-autosuggestions\n# plugins=(git docker macos bun zsh-autosuggestions)\n</code></pre></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000012\",\"markdownTextarea\":\"```bash\\n# oh-my-zsh\\nsh -c \\\"$(curl -fsSL https://install.ohmyz.sh)\\\"\\n# zsh-autosuggestions (plugin custom) + activarlo en ~/.zshrc\\ngit clone https://github.com/zsh-users/zsh-autosuggestions \\\\\\n  ${ZSH_CUSTOM:-~/.oh-my-zsh/custom}/plugins/zsh-autosuggestions\\n# plugins=(git docker macos bun zsh-autosuggestions)\\n```\",\"markdownTextareaHtml\":\"<pre><code class=\\\"language-bash\\\"># oh-my-zsh\\nsh -c &quot;$(curl -fsSL https://install.ohmyz.sh)&quot;\\n# zsh-autosuggestions (plugin custom) + activarlo en ~/.zshrc\\ngit clone https://github.com/zsh-users/zsh-autosuggestions \\\\\\n  ${ZSH_CUSTOM:-~/.oh-my-zsh/custom}/plugins/zsh-autosuggestions\\n# plugins=(git docker macos bun zsh-autosuggestions)\\n</code></pre>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000013":{"name":"Notas del ponente","order":3,"idevices":{"SP00000014":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p><strong>Demo (30s):</strong> abre una terminal limpia, escribe <code>git</code> y deja que aparezca la sugerencia fantasma; acéptala con la flecha. Escribe <code>cd ~/Dr</code> y enseña el autocompletado.</p>\n<p>Idea a transmitir: <strong>no memorizas comandos, los reconoces</strong>. El shell recuerda por ti. Menciona que esto vale para bash (<code>ble.sh</code>, <code>fzf</code>) y para fish sin configurar nada.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000014\",\"markdownTextarea\":\"**Demo (30s):** abre una terminal limpia, escribe `git ` y deja que aparezca la sugerencia fantasma; acéptala con la flecha. Escribe `cd ~/Dr` y enseña el autocompletado.\\n\\nIdea a transmitir: **no memorizas comandos, los reconoces**. El shell recuerda por ti. Menciona que esto vale para bash (`ble.sh`, `fzf`) y para fish sin configurar nada.\",\"markdownTextareaHtml\":\"<p><strong>Demo (30s):</strong> abre una terminal limpia, escribe <code>git</code> y deja que aparezca la sugerencia fantasma; acéptala con la flecha. Escribe <code>cd ~/Dr</code> y enseña el autocompletado.</p>\\n<p>Idea a transmitir: <strong>no memorizas comandos, los reconoces</strong>. El shell recuerda por ti. Menciona que esto vale para bash (<code>ble.sh</code>, <code>fzf</code>) y para fish sin configurar nada.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000015":{"name":"Mis scripts","isIndex":false,"fileName":"mis-scripts.html","fileUrl":"html/mis-scripts.html","prePageId":"SP00000008","nextPageId":"SP00000022","blocks":{"SP00000016":{"name":"Automatizar lo que repites cada día","order":1,"idevices":{"SP00000017":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Dos scripts míos, pequeños y con <strong>enorme retorno</strong>:</p>\n<ul>\n<li><strong><code>finder</code></strong> — abre Finder en un directorio (o en el actual). Salto terminal ↔ Finder sin soltar el teclado.</li>\n<li><strong><code>prs</code></strong> — panel de <strong>PRs e issues abiertos</strong> en todos mis repos (<code>ateeducacion</code> + <code>erseco</code>) vía <code>gh</code> (GraphQL) + <code>jq</code>, con <strong>hyperlinks</strong> clicables en el propio terminal. Un vistazo y sé qué tengo pendiente.</li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000017\",\"markdownTextarea\":\"Dos scripts míos, pequeños y con **enorme retorno**:\\n\\n- **`finder`** — abre Finder en un directorio (o en el actual). Salto terminal ↔ Finder sin soltar el teclado.\\n- **`prs`** — panel de **PRs e issues abiertos** en todos mis repos (`ateeducacion` + `erseco`) vía `gh` (GraphQL) + `jq`, con **hyperlinks** clicables en el propio terminal. Un vistazo y sé qué tengo pendiente.\",\"markdownTextareaHtml\":\"<p>Dos scripts míos, pequeños y con <strong>enorme retorno</strong>:</p>\\n<ul>\\n<li><strong><code>finder</code></strong> — abre Finder en un directorio (o en el actual). Salto terminal ↔ Finder sin soltar el teclado.</li>\\n<li><strong><code>prs</code></strong> — panel de <strong>PRs e issues abiertos</strong> en todos mis repos (<code>ateeducacion</code> + <code>erseco</code>) vía <code>gh</code> (GraphQL) + <code>jq</code>, con <strong>hyperlinks</strong> clicables en el propio terminal. Un vistazo y sé qué tengo pendiente.</li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000018":{"name":"Así se usan","order":2,"idevices":{"SP00000019":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><pre><code class=\"language-bash\">finder            # abre Finder aquí\nfinder ~/Downloads\n\nprs               # tabla de PRs/issues abiertos por repo,\n                  # ordenada por actividad, con enlaces clicables\n# por dentro: gh api graphql + jq (+ hyperlinks de terminal)\n</code></pre>\n<blockquote>\n<p>No hace falta una herramienta enorme: <strong>una función en tu <code>.zshrc</code></strong> que uses 20 veces al día ya paga el rato de escribirla.</p>\n</blockquote></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000019\",\"markdownTextarea\":\"```bash\\nfinder            # abre Finder aquí\\nfinder ~/Downloads\\n\\nprs               # tabla de PRs/issues abiertos por repo,\\n                  # ordenada por actividad, con enlaces clicables\\n# por dentro: gh api graphql + jq (+ hyperlinks de terminal)\\n```\\n\\n> No hace falta una herramienta enorme: **una función en tu `.zshrc`** que uses 20 veces al día ya paga el rato de escribirla.\",\"markdownTextareaHtml\":\"<pre><code class=\\\"language-bash\\\">finder            # abre Finder aquí\\nfinder ~/Downloads\\n\\nprs               # tabla de PRs/issues abiertos por repo,\\n                  # ordenada por actividad, con enlaces clicables\\n# por dentro: gh api graphql + jq (+ hyperlinks de terminal)\\n</code></pre>\\n<blockquote>\\n<p>No hace falta una herramienta enorme: <strong>una función en tu <code>.zshrc</code></strong> que uses 20 veces al día ya paga el rato de escribirla.</p>\\n</blockquote>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000020":{"name":"Notas del ponente","order":3,"idevices":{"SP00000021":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p><strong>Demo:</strong> ejecuta <code>prs</code> en vivo — es lo más vistoso de esta sección. Enseña que los enlaces son clicables (cmd+click) y que reúne varias organizaciones.</p>\n<p>Mensaje: guarda estos scripts en tus <strong>dotfiles</strong> (repo versionado). Lo que vive solo en tu máquina se pierde al cambiar de portátil; en git te sigue a todas partes y lo compartes con el equipo.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000021\",\"markdownTextarea\":\"**Demo:** ejecuta `prs` en vivo — es lo más vistoso de esta sección. Enseña que los enlaces son clicables (cmd+click) y que reúne varias organizaciones.\\n\\nMensaje: guarda estos scripts en tus **dotfiles** (repo versionado). Lo que vive solo en tu máquina se pierde al cambiar de portátil; en git te sigue a todas partes y lo compartes con el equipo.\",\"markdownTextareaHtml\":\"<p><strong>Demo:</strong> ejecuta <code>prs</code> en vivo — es lo más vistoso de esta sección. Enseña que los enlaces son clicables (cmd+click) y que reúne varias organizaciones.</p>\\n<p>Mensaje: guarda estos scripts en tus <strong>dotfiles</strong> (repo versionado). Lo que vive solo en tu máquina se pierde al cambiar de portátil; en git te sigue a todas partes y lo compartes con el equipo.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000022":{"name":"Gestores de paquetes","isIndex":false,"fileName":"gestores-de-paquetes.html","fileUrl":"html/gestores-de-paquetes.html","prePageId":"SP00000015","nextPageId":"SP00000029","blocks":{"SP00000023":{"name":"brew / apt-get / winget: el mismo concepto","order":1,"idevices":{"SP00000024":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Instalar y actualizar software <strong>desde el terminal</strong>, reproducible y scriptable.</p>\n<ul>\n<li><strong>macOS → Homebrew (<code>brew</code>)</strong>: para mí es un <em>must</em>. Todo (CLI y apps) desde un sitio.</li>\n<li><strong>Linux → <code>apt-get</code></strong> (o <code>dnf</code>, <code>pacman</code>…).</li>\n<li><strong>Windows → <code>winget</code></strong>.</li>\n</ul>\n<p>Cambia el comando, no la idea: <strong>un gestor declara tu entorno</strong>. Ese mismo concepto reaparece luego en Docker y en la CI.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000024\",\"markdownTextarea\":\"Instalar y actualizar software **desde el terminal**, reproducible y scriptable.\\n\\n- **macOS → Homebrew (`brew`)**: para mí es un *must*. Todo (CLI y apps) desde un sitio.\\n- **Linux → `apt-get`** (o `dnf`, `pacman`…).\\n- **Windows → `winget`**.\\n\\nCambia el comando, no la idea: **un gestor declara tu entorno**. Ese mismo concepto reaparece luego en Docker y en la CI.\",\"markdownTextareaHtml\":\"<p>Instalar y actualizar software <strong>desde el terminal</strong>, reproducible y scriptable.</p>\\n<ul>\\n<li><strong>macOS → Homebrew (<code>brew</code>)</strong>: para mí es un <em>must</em>. Todo (CLI y apps) desde un sitio.</li>\\n<li><strong>Linux → <code>apt-get</code></strong> (o <code>dnf</code>, <code>pacman</code>…).</li>\\n<li><strong>Windows → <code>winget</code></strong>.</li>\\n</ul>\\n<p>Cambia el comando, no la idea: <strong>un gestor declara tu entorno</strong>. Ese mismo concepto reaparece luego en Docker y en la CI.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000025":{"name":"El mismo entorno en tres sistemas","order":2,"idevices":{"SP00000026":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><pre><code class=\"language-bash\"># macOS\nbrew install ncdu gh jq bun\n# Debian / Ubuntu\nsudo apt-get install -y ncdu gh jq\n# Windows\nwinget install jqlang.jq GitHub.cli\n</code></pre>\n<p>Aviso: los catálogos difieren un poco entre sistemas, pero el flujo \"un comando para montar mi entorno\" es idéntico.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000026\",\"markdownTextarea\":\"```bash\\n# macOS\\nbrew install ncdu gh jq bun\\n# Debian / Ubuntu\\nsudo apt-get install -y ncdu gh jq\\n# Windows\\nwinget install jqlang.jq GitHub.cli\\n```\\n\\nAviso: los catálogos difieren un poco entre sistemas, pero el flujo \\\"un comando para montar mi entorno\\\" es idéntico.\",\"markdownTextareaHtml\":\"<pre><code class=\\\"language-bash\\\"># macOS\\nbrew install ncdu gh jq bun\\n# Debian / Ubuntu\\nsudo apt-get install -y ncdu gh jq\\n# Windows\\nwinget install jqlang.jq GitHub.cli\\n</code></pre>\\n<p>Aviso: los catálogos difieren un poco entre sistemas, pero el flujo \\\"un comando para montar mi entorno\\\" es idéntico.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000027":{"name":"Notas del ponente","order":3,"idevices":{"SP00000028":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Aquí planta la semilla que recogerás en la sección de CI: <strong>si tu entorno se instala con un comando, ya casi tienes tu CI escrita</strong>. Un <code>Makefile</code> o un <code>Dockerfile</code> no son más que esa misma lista de <code>install</code> puesta en orden.</p>\n<p>En Windows, recomienda combinar <code>winget</code> con <strong>WSL2</strong> para tener las mismas herramientas Unix que en mac/Linux.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000028\",\"markdownTextarea\":\"Aquí planta la semilla que recogerás en la sección de CI: **si tu entorno se instala con un comando, ya casi tienes tu CI escrita**. Un `Makefile` o un `Dockerfile` no son más que esa misma lista de `install` puesta en orden.\\n\\nEn Windows, recomienda combinar `winget` con **WSL2** para tener las mismas herramientas Unix que en mac/Linux.\",\"markdownTextareaHtml\":\"<p>Aquí planta la semilla que recogerás en la sección de CI: <strong>si tu entorno se instala con un comando, ya casi tienes tu CI escrita</strong>. Un <code>Makefile</code> o un <code>Dockerfile</code> no son más que esa misma lista de <code>install</code> puesta en orden.</p>\\n<p>En Windows, recomienda combinar <code>winget</code> con <strong>WSL2</strong> para tener las mismas herramientas Unix que en mac/Linux.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000029":{"name":"Utilidades del día a día","isIndex":false,"fileName":"utilidades-del-dia-a-dia.html","fileUrl":"html/utilidades-del-dia-a-dia.html","prePageId":"SP00000022","nextPageId":"SP00000036","blocks":{"SP00000030":{"name":"Tres que uso constantemente","order":1,"idevices":{"SP00000031":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><ul>\n<li><strong>Amphetamine</strong> (macOS) / <strong>Caffeine</strong> (Windows) — evitan que el equipo se <strong>suspenda</strong>: builds largos, tests, descargas o una demo que no se corta a mitad.</li>\n<li><strong>ncdu</strong> — <em>disk usage</em> navegable en el terminal: ordena por tamaño y encuentras al instante quién se come el disco (<code>node_modules</code>, imágenes de Docker, cachés).</li>\n<li><strong>codexbar</strong> — monitor de <strong>uso y tokens de IA</strong> en la barra de menú: sé en todo momento cómo voy de consumo con los agentes.</li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000031\",\"markdownTextarea\":\"- **Amphetamine** (macOS) / **Caffeine** (Windows) — evitan que el equipo se **suspenda**: builds largos, tests, descargas o una demo que no se corta a mitad.\\n- **ncdu** — *disk usage* navegable en el terminal: ordena por tamaño y encuentras al instante quién se come el disco (`node_modules`, imágenes de Docker, cachés).\\n- **codexbar** — monitor de **uso y tokens de IA** en la barra de menú: sé en todo momento cómo voy de consumo con los agentes.\",\"markdownTextareaHtml\":\"<ul>\\n<li><strong>Amphetamine</strong> (macOS) / <strong>Caffeine</strong> (Windows) — evitan que el equipo se <strong>suspenda</strong>: builds largos, tests, descargas o una demo que no se corta a mitad.</li>\\n<li><strong>ncdu</strong> — <em>disk usage</em> navegable en el terminal: ordena por tamaño y encuentras al instante quién se come el disco (<code>node_modules</code>, imágenes de Docker, cachés).</li>\\n<li><strong>codexbar</strong> — monitor de <strong>uso y tokens de IA</strong> en la barra de menú: sé en todo momento cómo voy de consumo con los agentes.</li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000032":{"name":"ncdu en 5 segundos","order":2,"idevices":{"SP00000033":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><pre><code class=\"language-bash\">ncdu ~                    # navega tu home, ordenado por tamaño\nncdu / --exclude /proc    # todo el disco\n# dentro: flechas para navegar, 'd' borra, 'q' sale\n</code></pre>\n<p>Encontrar 30 GB de <code>node_modules</code> y cachés viejas suele ser cuestión de segundos.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000033\",\"markdownTextarea\":\"```bash\\nncdu ~                    # navega tu home, ordenado por tamaño\\nncdu / --exclude /proc    # todo el disco\\n# dentro: flechas para navegar, 'd' borra, 'q' sale\\n```\\n\\nEncontrar 30 GB de `node_modules` y cachés viejas suele ser cuestión de segundos.\",\"markdownTextareaHtml\":\"<pre><code class=\\\"language-bash\\\">ncdu ~                    # navega tu home, ordenado por tamaño\\nncdu / --exclude /proc    # todo el disco\\n# dentro: flechas para navegar, 'd' borra, 'q' sale\\n</code></pre>\\n<p>Encontrar 30 GB de <code>node_modules</code> y cachés viejas suele ser cuestión de segundos.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000034":{"name":"Notas del ponente","order":3,"idevices":{"SP00000035":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p><strong>codexbar:</strong> describe genérico — una app de barra de menú que muestra el consumo de tokens/uso de las herramientas de IA de código (Claude Code / Codex). El punto no es la app concreta, sino <strong>tener visibilidad del coste</strong> cuando delegas trabajo en agentes: si no lo mides, no lo controlas.</p>\n<p><strong>Amphetamine:</strong> cuenta la anécdota del portátil que se duerme a mitad de un build o de una demo. Pequeño, pero salva presentaciones.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000035\",\"markdownTextarea\":\"**codexbar:** describe genérico — una app de barra de menú que muestra el consumo de tokens/uso de las herramientas de IA de código (Claude Code / Codex). El punto no es la app concreta, sino **tener visibilidad del coste** cuando delegas trabajo en agentes: si no lo mides, no lo controlas.\\n\\n**Amphetamine:** cuenta la anécdota del portátil que se duerme a mitad de un build o de una demo. Pequeño, pero salva presentaciones.\",\"markdownTextareaHtml\":\"<p><strong>codexbar:</strong> describe genérico — una app de barra de menú que muestra el consumo de tokens/uso de las herramientas de IA de código (Claude Code / Codex). El punto no es la app concreta, sino <strong>tener visibilidad del coste</strong> cuando delegas trabajo en agentes: si no lo mides, no lo controlas.</p>\\n<p><strong>Amphetamine:</strong> cuenta la anécdota del portátil que se duerme a mitad de un build o de una demo. Pequeño, pero salva presentaciones.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000036":{"name":"Cómo uso la IA","isIndex":false,"fileName":"como-uso-la-ia.html","fileUrl":"html/como-uso-la-ia.html","prePageId":"SP00000029","nextPageId":"SP00000041","blocks":{"SP00000037":{"name":"Chat ≠ autocomplete ≠ agente","order":1,"idevices":{"SP00000038":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><ul>\n<li><strong>Chat</strong>: preguntas y respuestas; copias y pegas tú.</li>\n<li><strong>Autocomplete</strong>: sugiere mientras escribes.</li>\n<li><strong>Agente</strong> (lo que más uso, p. ej. <strong>Claude Code</strong>): tiene <strong>herramientas</strong> y <strong>bucle</strong> — lee el repo, ejecuta comandos, modifica archivos, corre tests y abre PRs.</li>\n</ul>\n<blockquote>\n<p>La diferencia no es \"más listo\", es <strong>cuánto le dejas tocar</strong> y con qué contexto.</p>\n</blockquote>\n<p>Y la clave de todo: <strong>la IA es tan buena como el contexto que le das.</strong> Las tres cosas que siguen —MCP, skills, instrucciones— son formas de darle ese contexto.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000038\",\"markdownTextarea\":\"- **Chat**: preguntas y respuestas; copias y pegas tú.\\n- **Autocomplete**: sugiere mientras escribes.\\n- **Agente** (lo que más uso, p. ej. **Claude Code**): tiene **herramientas** y **bucle** — lee el repo, ejecuta comandos, modifica archivos, corre tests y abre PRs.\\n\\n> La diferencia no es \\\"más listo\\\", es **cuánto le dejas tocar** y con qué contexto.\\n\\nY la clave de todo: **la IA es tan buena como el contexto que le das.** Las tres cosas que siguen —MCP, skills, instrucciones— son formas de darle ese contexto.\",\"markdownTextareaHtml\":\"<ul>\\n<li><strong>Chat</strong>: preguntas y respuestas; copias y pegas tú.</li>\\n<li><strong>Autocomplete</strong>: sugiere mientras escribes.</li>\\n<li><strong>Agente</strong> (lo que más uso, p. ej. <strong>Claude Code</strong>): tiene <strong>herramientas</strong> y <strong>bucle</strong> — lee el repo, ejecuta comandos, modifica archivos, corre tests y abre PRs.</li>\\n</ul>\\n<blockquote>\\n<p>La diferencia no es \\\"más listo\\\", es <strong>cuánto le dejas tocar</strong> y con qué contexto.</p>\\n</blockquote>\\n<p>Y la clave de todo: <strong>la IA es tan buena como el contexto que le das.</strong> Las tres cosas que siguen —MCP, skills, instrucciones— son formas de darle ese contexto.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000039":{"name":"Notas del ponente","order":2,"idevices":{"SP00000040":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Este es el <strong>único</strong> tramo conceptual de la charla; que sea corto (2 min). Sirve de marco para las cuatro diapos siguientes: MCP (herramientas), skills (recetas), prompts/instrucciones (contexto) y el ejemplo real de ADRs.</p>\n<p>Aviso honesto: todo esto vale para cualquier IA de código (Copilot, Cursor, Codex…), no solo Claude Code. Yo enseño lo que uso, pero los conceptos son transferibles.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000040\",\"markdownTextarea\":\"Este es el **único** tramo conceptual de la charla; que sea corto (2 min). Sirve de marco para las cuatro diapos siguientes: MCP (herramientas), skills (recetas), prompts/instrucciones (contexto) y el ejemplo real de ADRs.\\n\\nAviso honesto: todo esto vale para cualquier IA de código (Copilot, Cursor, Codex…), no solo Claude Code. Yo enseño lo que uso, pero los conceptos son transferibles.\",\"markdownTextareaHtml\":\"<p>Este es el <strong>único</strong> tramo conceptual de la charla; que sea corto (2 min). Sirve de marco para las cuatro diapos siguientes: MCP (herramientas), skills (recetas), prompts/instrucciones (contexto) y el ejemplo real de ADRs.</p>\\n<p>Aviso honesto: todo esto vale para cualquier IA de código (Copilot, Cursor, Codex…), no solo Claude Code. Yo enseño lo que uso, pero los conceptos son transferibles.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000041":{"name":"MCP: darle herramientas a la IA","isIndex":false,"fileName":"mcp-darle-herramientas-a-la-ia.html","fileUrl":"html/mcp-darle-herramientas-a-la-ia.html","prePageId":"SP00000036","nextPageId":"SP00000046","blocks":{"SP00000042":{"name":"Los MCP que uso","order":1,"idevices":{"SP00000043":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p><strong>MCP</strong> = conectar la IA a herramientas y datos externos.</p>\n<ul>\n<li><strong>context7</strong> — documentación <strong>actualizada</strong> de librerías.</li>\n<li><strong>chrome-devtools / claude-in-chrome</strong> — navegador y DevTools.</li>\n<li><strong>github</strong> — issues, PRs y repos.</li>\n<li><strong>exa</strong> — búsqueda web.</li>\n<li><strong>filesystem</strong> — acceso a archivos.</li>\n</ul>\n<blockquote>\n<p>Sin MCP la IA solo habla. Con MCP, <strong>actúa</strong>.</p>\n</blockquote></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000043\",\"markdownTextarea\":\"**MCP** = conectar la IA a herramientas y datos externos.\\n\\n- **context7** — documentación **actualizada** de librerías.\\n- **chrome-devtools / claude-in-chrome** — navegador y DevTools.\\n- **github** — issues, PRs y repos.\\n- **exa** — búsqueda web.\\n- **filesystem** — acceso a archivos.\\n\\n> Sin MCP la IA solo habla. Con MCP, **actúa**.\",\"markdownTextareaHtml\":\"<p><strong>MCP</strong> = conectar la IA a herramientas y datos externos.</p>\\n<ul>\\n<li><strong>context7</strong> — documentación <strong>actualizada</strong> de librerías.</li>\\n<li><strong>chrome-devtools / claude-in-chrome</strong> — navegador y DevTools.</li>\\n<li><strong>github</strong> — issues, PRs y repos.</li>\\n<li><strong>exa</strong> — búsqueda web.</li>\\n<li><strong>filesystem</strong> — acceso a archivos.</li>\\n</ul>\\n<blockquote>\\n<p>Sin MCP la IA solo habla. Con MCP, <strong>actúa</strong>.</p>\\n</blockquote>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000044":{"name":"Notas del ponente","order":2,"idevices":{"SP00000045":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Diapositiva de poco texto: <strong>explícala tú, no la leas</strong>. Un MCP (Model Context Protocol) es un enchufe estándar entre el modelo y una herramienta.</p>\n<p>Por cada uno, una frase:<br>\n- <strong>context7</strong>: le da los <strong>docs reales y recientes</strong> de la librería, así deja de <strong>inventarse APIs</strong> viejas o inexistentes. Es lo que más alucinaciones evita.<br>\n- <strong>chrome-devtools / claude-in-chrome</strong>: la IA abre el navegador, mira la consola, la red y el DOM → depurar web y automatizar pruebas.<br>\n- <strong>github</strong>: lee y escribe issues y PRs → convierte una conversación en trabajo trazable.<br>\n- <strong>exa</strong>: búsqueda web cuando necesita algo fuera del repo.<br>\n- <strong>filesystem</strong>: leer/escribir archivos fuera del proyecto actual.</p>\n<p>Remata: <strong>eliges qué MCP montas por proyecto</strong>; no todos, solo los que ese trabajo necesita.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000045\",\"markdownTextarea\":\"Diapositiva de poco texto: **explícala tú, no la leas**. Un MCP (Model Context Protocol) es un enchufe estándar entre el modelo y una herramienta.\\n\\nPor cada uno, una frase:\\n- **context7**: le da los **docs reales y recientes** de la librería, así deja de **inventarse APIs** viejas o inexistentes. Es lo que más alucinaciones evita.\\n- **chrome-devtools / claude-in-chrome**: la IA abre el navegador, mira la consola, la red y el DOM → depurar web y automatizar pruebas.\\n- **github**: lee y escribe issues y PRs → convierte una conversación en trabajo trazable.\\n- **exa**: búsqueda web cuando necesita algo fuera del repo.\\n- **filesystem**: leer/escribir archivos fuera del proyecto actual.\\n\\nRemata: **eliges qué MCP montas por proyecto**; no todos, solo los que ese trabajo necesita.\",\"markdownTextareaHtml\":\"<p>Diapositiva de poco texto: <strong>explícala tú, no la leas</strong>. Un MCP (Model Context Protocol) es un enchufe estándar entre el modelo y una herramienta.</p>\\n<p>Por cada uno, una frase:<br>\\n- <strong>context7</strong>: le da los <strong>docs reales y recientes</strong> de la librería, así deja de <strong>inventarse APIs</strong> viejas o inexistentes. Es lo que más alucinaciones evita.<br>\\n- <strong>chrome-devtools / claude-in-chrome</strong>: la IA abre el navegador, mira la consola, la red y el DOM → depurar web y automatizar pruebas.<br>\\n- <strong>github</strong>: lee y escribe issues y PRs → convierte una conversación en trabajo trazable.<br>\\n- <strong>exa</strong>: búsqueda web cuando necesita algo fuera del repo.<br>\\n- <strong>filesystem</strong>: leer/escribir archivos fuera del proyecto actual.</p>\\n<p>Remata: <strong>eliges qué MCP montas por proyecto</strong>; no todos, solo los que ese trabajo necesita.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000046":{"name":"Skills: recetas reutilizables","isIndex":false,"fileName":"skills-recetas-reutilizables.html","fileUrl":"html/skills-recetas-reutilizables.html","prePageId":"SP00000041","nextPageId":"SP00000051","blocks":{"SP00000047":{"name":"Capacidades empaquetadas","order":1,"idevices":{"SP00000048":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Una <strong>skill</strong> es un procedimiento o capacidad empaquetada que la IA invoca cuando toca. Las que uso:</p>\n<ul>\n<li><strong>superpowers</strong> — orquestación multi-agente: brainstorming, TDD, code review, debugging sistemático.</li>\n<li><strong>security-audit (Cloudflare)</strong> — auditoría de seguridad del código.</li>\n<li><strong>webwright</strong> — automatización y pruebas web con navegador real.</li>\n<li><strong>code-review</strong>, <strong>improve</strong>, <strong>modern-web-guidance</strong> — revisión, mejoras y buenas prácticas web al día.</li>\n</ul>\n<blockquote>\n<p>Skills = <strong>procesos</strong> que la IA sigue igual cada vez; no dependes de recordar el prompt perfecto.</p>\n</blockquote></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000048\",\"markdownTextarea\":\"Una **skill** es un procedimiento o capacidad empaquetada que la IA invoca cuando toca. Las que uso:\\n\\n- **superpowers** — orquestación multi-agente: brainstorming, TDD, code review, debugging sistemático.\\n- **security-audit (Cloudflare)** — auditoría de seguridad del código.\\n- **webwright** — automatización y pruebas web con navegador real.\\n- **code-review**, **improve**, **modern-web-guidance** — revisión, mejoras y buenas prácticas web al día.\\n\\n> Skills = **procesos** que la IA sigue igual cada vez; no dependes de recordar el prompt perfecto.\",\"markdownTextareaHtml\":\"<p>Una <strong>skill</strong> es un procedimiento o capacidad empaquetada que la IA invoca cuando toca. Las que uso:</p>\\n<ul>\\n<li><strong>superpowers</strong> — orquestación multi-agente: brainstorming, TDD, code review, debugging sistemático.</li>\\n<li><strong>security-audit (Cloudflare)</strong> — auditoría de seguridad del código.</li>\\n<li><strong>webwright</strong> — automatización y pruebas web con navegador real.</li>\\n<li><strong>code-review</strong>, <strong>improve</strong>, <strong>modern-web-guidance</strong> — revisión, mejoras y buenas prácticas web al día.</li>\\n</ul>\\n<blockquote>\\n<p>Skills = <strong>procesos</strong> que la IA sigue igual cada vez; no dependes de recordar el prompt perfecto.</p>\\n</blockquote>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000049":{"name":"Notas del ponente","order":2,"idevices":{"SP00000050":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Diferencia clara: <strong>MCP = herramientas</strong> (con qué actúa); <strong>skill = receta/proceso</strong> (cómo trabaja). Se combinan.</p>\n<p>Destaca los que pediste enseñar:<br>\n- <strong>security-audit</strong> de Cloudflare: pídele \"haz una auditoría de seguridad de este código\" y aplica una metodología, no improvisa.<br>\n- <strong>superpowers</strong>: convierte una tarea en un flujo con fases (planificar → implementar con TDD → revisar) y hasta lanza subagentes en paralelo.<br>\n- <strong>webwright</strong>: automatiza tareas web reproducibles con capturas de evidencia.</p>\n<p>Si hay tiempo, lanza una skill en vivo (p. ej. una mini auditoría o un code-review del diff actual).</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000050\",\"markdownTextarea\":\"Diferencia clara: **MCP = herramientas** (con qué actúa); **skill = receta/proceso** (cómo trabaja). Se combinan.\\n\\nDestaca los que pediste enseñar:\\n- **security-audit** de Cloudflare: pídele \\\"haz una auditoría de seguridad de este código\\\" y aplica una metodología, no improvisa.\\n- **superpowers**: convierte una tarea en un flujo con fases (planificar → implementar con TDD → revisar) y hasta lanza subagentes en paralelo.\\n- **webwright**: automatiza tareas web reproducibles con capturas de evidencia.\\n\\nSi hay tiempo, lanza una skill en vivo (p. ej. una mini auditoría o un code-review del diff actual).\",\"markdownTextareaHtml\":\"<p>Diferencia clara: <strong>MCP = herramientas</strong> (con qué actúa); <strong>skill = receta/proceso</strong> (cómo trabaja). Se combinan.</p>\\n<p>Destaca los que pediste enseñar:<br>\\n- <strong>security-audit</strong> de Cloudflare: pídele \\\"haz una auditoría de seguridad de este código\\\" y aplica una metodología, no improvisa.<br>\\n- <strong>superpowers</strong>: convierte una tarea en un flujo con fases (planificar → implementar con TDD → revisar) y hasta lanza subagentes en paralelo.<br>\\n- <strong>webwright</strong>: automatiza tareas web reproducibles con capturas de evidencia.</p>\\n<p>Si hay tiempo, lanza una skill en vivo (p. ej. una mini auditoría o un code-review del diff actual).</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000051":{"name":"Prompts de calidad y contexto","isIndex":false,"fileName":"prompts-de-calidad-y-contexto.html","fileUrl":"html/prompts-de-calidad-y-contexto.html","prePageId":"SP00000046","nextPageId":"SP00000058","blocks":{"SP00000052":{"name":"Un buen prompt + contexto de GitHub","order":1,"idevices":{"SP00000053":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>La calidad de la salida = calidad de la <strong>tarea</strong> que planteas.</p>\n<p>Un buen encargo lleva:</p>\n<ul>\n<li><strong>Objetivo</strong> claro y acotado.</li>\n<li><strong>Restricciones</strong>: qué <strong>NO</strong> tocar.</li>\n<li><strong>Criterio de \"hecho\"</strong> y <strong>tests</strong>.</li>\n</ul>\n<p>Y enséñale a <strong>leer GitHub</strong> (issues, PRs, código) para que genere tareas de calidad con el contexto real del proyecto, no con suposiciones.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000053\",\"markdownTextarea\":\"La calidad de la salida = calidad de la **tarea** que planteas.\\n\\nUn buen encargo lleva:\\n\\n- **Objetivo** claro y acotado.\\n- **Restricciones**: qué **NO** tocar.\\n- **Criterio de \\\"hecho\\\"** y **tests**.\\n\\nY enséñale a **leer GitHub** (issues, PRs, código) para que genere tareas de calidad con el contexto real del proyecto, no con suposiciones.\",\"markdownTextareaHtml\":\"<p>La calidad de la salida = calidad de la <strong>tarea</strong> que planteas.</p>\\n<p>Un buen encargo lleva:</p>\\n<ul>\\n<li><strong>Objetivo</strong> claro y acotado.</li>\\n<li><strong>Restricciones</strong>: qué <strong>NO</strong> tocar.</li>\\n<li><strong>Criterio de \\\"hecho\\\"</strong> y <strong>tests</strong>.</li>\\n</ul>\\n<p>Y enséñale a <strong>leer GitHub</strong> (issues, PRs, código) para que genere tareas de calidad con el contexto real del proyecto, no con suposiciones.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000054":{"name":"Instrucciones personalizadas = contexto permanente","order":2,"idevices":{"SP00000055":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Lo que no quieres repetir en cada prompt, escríbelo una vez en <code>CLAUDE.md</code> / <code>AGENTS.md</code>: convenciones, estándares, \"nunca toques secretos\", idioma de los comentarios…</p>\n<ul>\n<li>Es el <strong>contexto que la IA lee siempre</strong>, en todo el repo.</li>\n<li>Mis instrucciones personalizadas → <strong><code><TODO: enlace a mis instrucciones personalizadas></code></strong></li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000055\",\"markdownTextarea\":\"Lo que no quieres repetir en cada prompt, escríbelo una vez en `CLAUDE.md` / `AGENTS.md`: convenciones, estándares, \\\"nunca toques secretos\\\", idioma de los comentarios…\\n\\n- Es el **contexto que la IA lee siempre**, en todo el repo.\\n- Mis instrucciones personalizadas → **`<TODO: enlace a mis instrucciones personalizadas>`**\",\"markdownTextareaHtml\":\"<p>Lo que no quieres repetir en cada prompt, escríbelo una vez en <code>CLAUDE.md</code> / <code>AGENTS.md</code>: convenciones, estándares, \\\"nunca toques secretos\\\", idioma de los comentarios…</p>\\n<ul>\\n<li>Es el <strong>contexto que la IA lee siempre</strong>, en todo el repo.</li>\\n<li>Mis instrucciones personalizadas → <strong><code>&lt;TODO: enlace a mis instrucciones personalizadas&gt;</code></strong></li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000056":{"name":"Notas del ponente","order":3,"idevices":{"SP00000057":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p><strong>Recuerda rellenar el placeholder del enlace</strong> antes de la charla (o quítalo).</p>\n<p>Ejemplo concreto de \"enseñarle a leer GitHub\": en vez de describir un bug a mano, dile <em>\"lee el issue #123 y su hilo, mira el PR relacionado y propón un plan\"</em>. El contexto lo saca del repo, no de tu memoria.</p>\n<p>Encadena con la siguiente diapo: la mejor forma de que ese contexto sea <strong>permanente y trazable</strong> no es un prompt largo, es un <strong>sistema</strong> — y eso es exactamente lo que hago en mod_exelearning con los ADRs.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000057\",\"markdownTextarea\":\"**Recuerda rellenar el placeholder del enlace** antes de la charla (o quítalo).\\n\\nEjemplo concreto de \\\"enseñarle a leer GitHub\\\": en vez de describir un bug a mano, dile *\\\"lee el issue #123 y su hilo, mira el PR relacionado y propón un plan\\\"*. El contexto lo saca del repo, no de tu memoria.\\n\\nEncadena con la siguiente diapo: la mejor forma de que ese contexto sea **permanente y trazable** no es un prompt largo, es un **sistema** — y eso es exactamente lo que hago en mod_exelearning con los ADRs.\",\"markdownTextareaHtml\":\"<p><strong>Recuerda rellenar el placeholder del enlace</strong> antes de la charla (o quítalo).</p>\\n<p>Ejemplo concreto de \\\"enseñarle a leer GitHub\\\": en vez de describir un bug a mano, dile <em>\\\"lee el issue #123 y su hilo, mira el PR relacionado y propón un plan\\\"</em>. El contexto lo saca del repo, no de tu memoria.</p>\\n<p>Encadena con la siguiente diapo: la mejor forma de que ese contexto sea <strong>permanente y trazable</strong> no es un prompt largo, es un <strong>sistema</strong> — y eso es exactamente lo que hago en mod_exelearning con los ADRs.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000058":{"name":"Ejemplo real: mod_exelearning + ADRs","isIndex":false,"fileName":"ejemplo-real-modexelearning-adrs.html","fileUrl":"html/ejemplo-real-modexelearning-adrs.html","prePageId":"SP00000051","nextPageId":"SP00000065","blocks":{"SP00000059":{"name":"Que la IA desarrolle y documente TODO, trazable","order":1,"idevices":{"SP00000060":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p><strong>mod_exelearning</strong> — mi plugin de Moodle para embeber unidades de eXeLearning. Reto: usar IA para avanzar rápido <strong>sin perder</strong> la trazabilidad de por qué está hecho cada cosa.</p>\n<p>Solución: un sistema de <strong>ADR</strong> (Architecture Decision Records). Cada decisión es un documento <strong><code>DEC-NNNN</code></strong> con secciones fijas: <em>Contexto · Problema · Opciones · Evidencia · Decisión · Consecuencias · Riesgos · Validación · Seguimiento</em>.</p>\n<ul>\n<li><strong>60+ ADRs</strong>, numeración monótona, índices auto-generados.</li>\n<li>Regla de oro: <strong>\"sin fuente no hay afirmación\"</strong> (cada dato cita repo+ruta+commit, doc oficial o experimento).</li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000060\",\"markdownTextarea\":\"**mod_exelearning** — mi plugin de Moodle para embeber unidades de eXeLearning. Reto: usar IA para avanzar rápido **sin perder** la trazabilidad de por qué está hecho cada cosa.\\n\\nSolución: un sistema de **ADR** (Architecture Decision Records). Cada decisión es un documento **`DEC-NNNN`** con secciones fijas: *Contexto · Problema · Opciones · Evidencia · Decisión · Consecuencias · Riesgos · Validación · Seguimiento*.\\n\\n- **60+ ADRs**, numeración monótona, índices auto-generados.\\n- Regla de oro: **\\\"sin fuente no hay afirmación\\\"** (cada dato cita repo+ruta+commit, doc oficial o experimento).\",\"markdownTextareaHtml\":\"<p><strong>mod_exelearning</strong> — mi plugin de Moodle para embeber unidades de eXeLearning. Reto: usar IA para avanzar rápido <strong>sin perder</strong> la trazabilidad de por qué está hecho cada cosa.</p>\\n<p>Solución: un sistema de <strong>ADR</strong> (Architecture Decision Records). Cada decisión es un documento <strong><code>DEC-NNNN</code></strong> con secciones fijas: <em>Contexto · Problema · Opciones · Evidencia · Decisión · Consecuencias · Riesgos · Validación · Seguimiento</em>.</p>\\n<ul>\\n<li><strong>60+ ADRs</strong>, numeración monótona, índices auto-generados.</li>\\n<li>Regla de oro: <strong>\\\"sin fuente no hay afirmación\\\"</strong> (cada dato cita repo+ruta+commit, doc oficial o experimento).</li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000061":{"name":"El frontmatter registra quién decidió (humano o IA)","order":2,"idevices":{"SP00000062":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><pre><code class=\"language-yaml\">id: DEC-0007\ntitulo: \"Gestión de intentos\"\nestado: Aceptada\nfecha: 2026-06-10\nagentes: [erseco, claude-code]\nherramienta_ia:\n  interfaz: claude-code\n  modelo: claude-opus-4-7\nfuentes: [REPO-042, FTE-011]\n</code></pre>\n<ul>\n<li>Cada ADR <strong>declara si lo escribió una persona o un agente</strong>, y con qué modelo.</li>\n<li>En el código, cada función <strong>cita su decisión</strong>: <code>// (DEC-0008)</code>.</li>\n<li><code>AGENTS.md</code> fija las reglas: <strong>Context7 obligatorio</strong> para APIs, tests con cada cambio, <code>phpcs --standard=moodle</code> a <strong>0/0</strong>, e índices regenerados como <em>Definition of Done</em>.</li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000062\",\"markdownTextarea\":\"```yaml\\nid: DEC-0007\\ntitulo: \\\"Gestión de intentos\\\"\\nestado: Aceptada\\nfecha: 2026-06-10\\nagentes: [erseco, claude-code]\\nherramienta_ia:\\n  interfaz: claude-code\\n  modelo: claude-opus-4-7\\nfuentes: [REPO-042, FTE-011]\\n```\\n\\n- Cada ADR **declara si lo escribió una persona o un agente**, y con qué modelo.\\n- En el código, cada función **cita su decisión**: `// (DEC-0008)`.\\n- `AGENTS.md` fija las reglas: **Context7 obligatorio** para APIs, tests con cada cambio, `phpcs --standard=moodle` a **0/0**, e índices regenerados como *Definition of Done*.\",\"markdownTextareaHtml\":\"<pre><code class=\\\"language-yaml\\\">id: DEC-0007\\ntitulo: &quot;Gestión de intentos&quot;\\nestado: Aceptada\\nfecha: 2026-06-10\\nagentes: [erseco, claude-code]\\nherramienta_ia:\\n  interfaz: claude-code\\n  modelo: claude-opus-4-7\\nfuentes: [REPO-042, FTE-011]\\n</code></pre>\\n<ul>\\n<li>Cada ADR <strong>declara si lo escribió una persona o un agente</strong>, y con qué modelo.</li>\\n<li>En el código, cada función <strong>cita su decisión</strong>: <code>// (DEC-0008)</code>.</li>\\n<li><code>AGENTS.md</code> fija las reglas: <strong>Context7 obligatorio</strong> para APIs, tests con cada cambio, <code>phpcs --standard=moodle</code> a <strong>0/0</strong>, e índices regenerados como <em>Definition of Done</em>.</li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000063":{"name":"Notas del ponente","order":3,"idevices":{"SP00000064":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Este es el <strong>clímax de la sección de IA</strong> y responde a \"que la IA desarrolle y documente todo\". El repo: <code>github.com/exelearning/mod_exelearning</code>.</p>\n<p>Mensajes:<br>\n- La IA no solo escribe código: <strong>escribe la justificación</strong> y la deja citable, igual que un humano. Un ADR escrito por <code>claude-code</code> se audita igual que uno mío.<br>\n- Cuentas incluso con <strong>auditorías multi-agente</strong> registradas como decisiones (p. ej. una de seguridad con 21 hallazgos, otra de bugs críticos). La IA revisa a la IA, y queda por escrito.<br>\n- Moraleja: no delegas el <strong>criterio</strong>, delegas la <strong>redacción disciplinada</strong>. El sistema (ADRs + AGENTS.md + índices validados) es lo que hace que la velocidad no cueste trazabilidad.</p>\n<p>Si vas bien de tiempo, abre un ADR real en pantalla y enseña el frontmatter y las secciones.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000064\",\"markdownTextarea\":\"Este es el **clímax de la sección de IA** y responde a \\\"que la IA desarrolle y documente todo\\\". El repo: `github.com/exelearning/mod_exelearning`.\\n\\nMensajes:\\n- La IA no solo escribe código: **escribe la justificación** y la deja citable, igual que un humano. Un ADR escrito por `claude-code` se audita igual que uno mío.\\n- Cuentas incluso con **auditorías multi-agente** registradas como decisiones (p. ej. una de seguridad con 21 hallazgos, otra de bugs críticos). La IA revisa a la IA, y queda por escrito.\\n- Moraleja: no delegas el **criterio**, delegas la **redacción disciplinada**. El sistema (ADRs + AGENTS.md + índices validados) es lo que hace que la velocidad no cueste trazabilidad.\\n\\nSi vas bien de tiempo, abre un ADR real en pantalla y enseña el frontmatter y las secciones.\",\"markdownTextareaHtml\":\"<p>Este es el <strong>clímax de la sección de IA</strong> y responde a \\\"que la IA desarrolle y documente todo\\\". El repo: <code>github.com/exelearning/mod_exelearning</code>.</p>\\n<p>Mensajes:<br>\\n- La IA no solo escribe código: <strong>escribe la justificación</strong> y la deja citable, igual que un humano. Un ADR escrito por <code>claude-code</code> se audita igual que uno mío.<br>\\n- Cuentas incluso con <strong>auditorías multi-agente</strong> registradas como decisiones (p. ej. una de seguridad con 21 hallazgos, otra de bugs críticos). La IA revisa a la IA, y queda por escrito.<br>\\n- Moraleja: no delegas el <strong>criterio</strong>, delegas la <strong>redacción disciplinada</strong>. El sistema (ADRs + AGENTS.md + índices validados) es lo que hace que la velocidad no cueste trazabilidad.</p>\\n<p>Si vas bien de tiempo, abre un ADR real en pantalla y enseña el frontmatter y las secciones.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000065":{"name":"IA: dónde sí y dónde no","isIndex":false,"fileName":"ia-donde-si-y-donde-no.html","fileUrl":"html/ia-donde-si-y-donde-no.html","prePageId":"SP00000058","nextPageId":"SP00000070","blocks":{"SP00000066":{"name":"Dónde ayuda de verdad","order":1,"idevices":{"SP00000067":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><ul>\n<li><strong>Explorar</strong> código desconocido.</li>\n<li><strong>Borradores</strong>: primer esqueleto de función o test.</li>\n<li><strong>Tests</strong> para código sin cobertura.</li>\n<li><strong>Refactors</strong> pequeños y mecánicos.</li>\n<li><strong>Explicar</strong> errores y trazas.</li>\n<li><strong>Documentación</strong> a partir del código real.</li>\n<li><strong>Primer filtro</strong> de revisión (no el último).</li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000067\",\"markdownTextarea\":\"- **Explorar** código desconocido.\\n- **Borradores**: primer esqueleto de función o test.\\n- **Tests** para código sin cobertura.\\n- **Refactors** pequeños y mecánicos.\\n- **Explicar** errores y trazas.\\n- **Documentación** a partir del código real.\\n- **Primer filtro** de revisión (no el último).\",\"markdownTextareaHtml\":\"<ul>\\n<li><strong>Explorar</strong> código desconocido.</li>\\n<li><strong>Borradores</strong>: primer esqueleto de función o test.</li>\\n<li><strong>Tests</strong> para código sin cobertura.</li>\\n<li><strong>Refactors</strong> pequeños y mecánicos.</li>\\n<li><strong>Explicar</strong> errores y trazas.</li>\\n<li><strong>Documentación</strong> a partir del código real.</li>\\n<li><strong>Primer filtro</strong> de revisión (no el último).</li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000068":{"name":"Dónde NO decide sola","order":2,"idevices":{"SP00000069":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><ul>\n<li><strong>Arquitectura</strong>: decisiones a años vista.</li>\n<li><strong>Seguridad</strong>: permisos, cripto, control de acceso.</li>\n<li><strong>Datos sensibles</strong>: RGPD, datos de alumnado, calificaciones.</li>\n<li><strong>Cambios masivos sin tests</strong>.</li>\n<li><strong>Dependencias críticas</strong> y <strong>producción</strong>.</li>\n</ul>\n<blockquote>\n<p>La IA <strong>propone</strong>; el humano <strong>dispone</strong>. Y pase lo que pase: <strong>revisa siempre el diff.</strong> Lo verde no es lo correcto.</p>\n</blockquote></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000069\",\"markdownTextarea\":\"- **Arquitectura**: decisiones a años vista.\\n- **Seguridad**: permisos, cripto, control de acceso.\\n- **Datos sensibles**: RGPD, datos de alumnado, calificaciones.\\n- **Cambios masivos sin tests**.\\n- **Dependencias críticas** y **producción**.\\n\\n> La IA **propone**; el humano **dispone**. Y pase lo que pase: **revisa siempre el diff.** Lo verde no es lo correcto.\",\"markdownTextareaHtml\":\"<ul>\\n<li><strong>Arquitectura</strong>: decisiones a años vista.</li>\\n<li><strong>Seguridad</strong>: permisos, cripto, control de acceso.</li>\\n<li><strong>Datos sensibles</strong>: RGPD, datos de alumnado, calificaciones.</li>\\n<li><strong>Cambios masivos sin tests</strong>.</li>\\n<li><strong>Dependencias críticas</strong> y <strong>producción</strong>.</li>\\n</ul>\\n<blockquote>\\n<p>La IA <strong>propone</strong>; el humano <strong>dispone</strong>. Y pase lo que pase: <strong>revisa siempre el diff.</strong> Lo verde no es lo correcto.</p>\\n</blockquote>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000070":{"name":"Make como interfaz única","isIndex":false,"fileName":"make-como-interfaz-unica.html","fileUrl":"html/make-como-interfaz-unica.html","prePageId":"SP00000065","nextPageId":"SP00000077","blocks":{"SP00000071":{"name":"Un Makefile, todas las máquinas","order":1,"idevices":{"SP00000072":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p><code>make</code> está en <strong>todos</strong> los sistemas (multiplataforma; da algo de trabajo, pero compensa).</p>\n<ul>\n<li>Una <strong>única interfaz</strong> para el proyecto: no memorizas comandos largos, ejecutas verbos.</li>\n<li><strong>Lo que corro en local = lo que corre la CI.</strong> El mismo <code>make test</code> en mi portátil y en GitHub Actions.</li>\n<li>Autodocumentado: <code>make help</code> lista lo que se puede hacer.</li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000072\",\"markdownTextarea\":\"`make` está en **todos** los sistemas (multiplataforma; da algo de trabajo, pero compensa).\\n\\n- Una **única interfaz** para el proyecto: no memorizas comandos largos, ejecutas verbos.\\n- **Lo que corro en local = lo que corre la CI.** El mismo `make test` en mi portátil y en GitHub Actions.\\n- Autodocumentado: `make help` lista lo que se puede hacer.\",\"markdownTextareaHtml\":\"<p><code>make</code> está en <strong>todos</strong> los sistemas (multiplataforma; da algo de trabajo, pero compensa).</p>\\n<ul>\\n<li>Una <strong>única interfaz</strong> para el proyecto: no memorizas comandos largos, ejecutas verbos.</li>\\n<li><strong>Lo que corro en local = lo que corre la CI.</strong> El mismo <code>make test</code> en mi portátil y en GitHub Actions.</li>\\n<li>Autodocumentado: <code>make help</code> lista lo que se puede hacer.</li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000073":{"name":"Ejemplo real (este repo de charlas)","order":2,"idevices":{"SP00000074":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><pre><code class=\"language-make\">make install   # dependencias\nmake validate  # comprobar metadatos de cada charla\nmake build     # validate + generar el sitio estático\nmake serve     # http://localhost:8080\nmake exe       # (local) regenerar la unidad eXeLearning\n</code></pre>\n<p>Esta misma presentación se construye con estos targets.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000074\",\"markdownTextarea\":\"```make\\nmake install   # dependencias\\nmake validate  # comprobar metadatos de cada charla\\nmake build     # validate + generar el sitio estático\\nmake serve     # http://localhost:8080\\nmake exe       # (local) regenerar la unidad eXeLearning\\n```\\n\\nEsta misma presentación se construye con estos targets.\",\"markdownTextareaHtml\":\"<pre><code class=\\\"language-make\\\">make install   # dependencias\\nmake validate  # comprobar metadatos de cada charla\\nmake build     # validate + generar el sitio estático\\nmake serve     # http://localhost:8080\\nmake exe       # (local) regenerar la unidad eXeLearning\\n</code></pre>\\n<p>Esta misma presentación se construye con estos targets.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000075":{"name":"Notas del ponente","order":3,"idevices":{"SP00000076":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Idea ancla de la sección: <strong>el Makefile es el contrato</strong>. Reduce la distancia entre \"funciona en mi máquina\" y \"funciona en la CI\" a cero, porque <strong>ejecutan literalmente lo mismo</strong>.</p>\n<p>Demo posible: <code>make help</code> en este repo, y luego enseña que el workflow de GitHub Actions llama a <code>make validate</code> y <code>make build</code> — los mismos verbos.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000076\",\"markdownTextarea\":\"Idea ancla de la sección: **el Makefile es el contrato**. Reduce la distancia entre \\\"funciona en mi máquina\\\" y \\\"funciona en la CI\\\" a cero, porque **ejecutan literalmente lo mismo**.\\n\\nDemo posible: `make help` en este repo, y luego enseña que el workflow de GitHub Actions llama a `make validate` y `make build` — los mismos verbos.\",\"markdownTextareaHtml\":\"<p>Idea ancla de la sección: <strong>el Makefile es el contrato</strong>. Reduce la distancia entre \\\"funciona en mi máquina\\\" y \\\"funciona en la CI\\\" a cero, porque <strong>ejecutan literalmente lo mismo</strong>.</p>\\n<p>Demo posible: <code>make help</code> en este repo, y luego enseña que el workflow de GitHub Actions llama a <code>make validate</code> y <code>make build</code> — los mismos verbos.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000077":{"name":"Entornos reproducibles","isIndex":false,"fileName":"entornos-reproducibles.html","fileUrl":"html/entornos-reproducibles.html","prePageId":"SP00000070","nextPageId":"SP00000082","blocks":{"SP00000078":{"name":"Docker, playgrounds y Alpine","order":1,"idevices":{"SP00000079":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><ul>\n<li><strong>Docker / playgrounds</strong>: entornos idénticos para todos; se acabó el <em>\"en mi máquina funciona\"</em>. Levantar y tirar entornos con un comando.</li>\n<li><strong>Alpine</strong> siempre que se pueda: imágenes <strong>pequeñas, rápidas y con menos superficie de ataque</strong>. Builds y despliegues más ágiles.</li>\n<li>Ejemplo: <strong>alpine-moodle</strong> — Moodle completo sobre Alpine, ligero y reproducible (<code>github.com/erseco/alpine-moodle</code>).</li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000079\",\"markdownTextarea\":\"- **Docker / playgrounds**: entornos idénticos para todos; se acabó el *\\\"en mi máquina funciona\\\"*. Levantar y tirar entornos con un comando.\\n- **Alpine** siempre que se pueda: imágenes **pequeñas, rápidas y con menos superficie de ataque**. Builds y despliegues más ágiles.\\n- Ejemplo: **alpine-moodle** — Moodle completo sobre Alpine, ligero y reproducible (`github.com/erseco/alpine-moodle`).\",\"markdownTextareaHtml\":\"<ul>\\n<li><strong>Docker / playgrounds</strong>: entornos idénticos para todos; se acabó el <em>\\\"en mi máquina funciona\\\"</em>. Levantar y tirar entornos con un comando.</li>\\n<li><strong>Alpine</strong> siempre que se pueda: imágenes <strong>pequeñas, rápidas y con menos superficie de ataque</strong>. Builds y despliegues más ágiles.</li>\\n<li>Ejemplo: <strong>alpine-moodle</strong> — Moodle completo sobre Alpine, ligero y reproducible (<code>github.com/erseco/alpine-moodle</code>).</li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000080":{"name":"Notas del ponente","order":2,"idevices":{"SP00000081":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Demo/enseña <strong>alpine-moodle</strong>: el contraste de tamaño de imagen frente a una basada en Debian es el argumento visual. Menos peso = pulls más rápidos, CI más rápida, menos CVEs que parchear.</p>\n<p>Conecta con la diapo anterior: el <code>Makefile</code> orquesta Docker; el gestor de paquetes de Alpine (<code>apk</code>) es el mismo concepto de \"declara tu entorno\" que brew/apt. Todo es la misma idea a distintas capas.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000081\",\"markdownTextarea\":\"Demo/enseña **alpine-moodle**: el contraste de tamaño de imagen frente a una basada en Debian es el argumento visual. Menos peso = pulls más rápidos, CI más rápida, menos CVEs que parchear.\\n\\nConecta con la diapo anterior: el `Makefile` orquesta Docker; el gestor de paquetes de Alpine (`apk`) es el mismo concepto de \\\"declara tu entorno\\\" que brew/apt. Todo es la misma idea a distintas capas.\",\"markdownTextareaHtml\":\"<p>Demo/enseña <strong>alpine-moodle</strong>: el contraste de tamaño de imagen frente a una basada en Debian es el argumento visual. Menos peso = pulls más rápidos, CI más rápida, menos CVEs que parchear.</p>\\n<p>Conecta con la diapo anterior: el <code>Makefile</code> orquesta Docker; el gestor de paquetes de Alpine (<code>apk</code>) es el mismo concepto de \\\"declara tu entorno\\\" que brew/apt. Todo es la misma idea a distintas capas.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000082":{"name":"CI = lo mismo que en local","isIndex":false,"fileName":"ci-lo-mismo-que-en-local.html","fileUrl":"html/ci-lo-mismo-que-en-local.html","prePageId":"SP00000077","nextPageId":"SP00000087","blocks":{"SP00000083":{"name":"Reproducir el fallo deja de ser una lotería","order":1,"idevices":{"SP00000084":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Los tests que fallan en la CI tienen que poder fallar <strong>en tu máquina</strong>.</p>\n<p>En Moodle/PHP, <strong>moodle-plugin-ci</strong> ejecuta en local exactamente lo mismo que el pipeline:</p>\n<pre><code class=\"language-bash\">moodle-plugin-ci phpcs      # estándar de código de Moodle\nmoodle-plugin-ci phpunit    # tests unitarios\nmoodle-plugin-ci behat      # tests de aceptación\nmoodle-plugin-ci validate   # manifiesto del plugin\n</code></pre></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000084\",\"markdownTextarea\":\"Los tests que fallan en la CI tienen que poder fallar **en tu máquina**.\\n\\nEn Moodle/PHP, **moodle-plugin-ci** ejecuta en local exactamente lo mismo que el pipeline:\\n\\n```bash\\nmoodle-plugin-ci phpcs      # estándar de código de Moodle\\nmoodle-plugin-ci phpunit    # tests unitarios\\nmoodle-plugin-ci behat      # tests de aceptación\\nmoodle-plugin-ci validate   # manifiesto del plugin\\n```\",\"markdownTextareaHtml\":\"<p>Los tests que fallan en la CI tienen que poder fallar <strong>en tu máquina</strong>.</p>\\n<p>En Moodle/PHP, <strong>moodle-plugin-ci</strong> ejecuta en local exactamente lo mismo que el pipeline:</p>\\n<pre><code class=\\\"language-bash\\\">moodle-plugin-ci phpcs      # estándar de código de Moodle\\nmoodle-plugin-ci phpunit    # tests unitarios\\nmoodle-plugin-ci behat      # tests de aceptación\\nmoodle-plugin-ci validate   # manifiesto del plugin\\n</code></pre>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000085":{"name":"Notas del ponente","order":2,"idevices":{"SP00000086":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Mensaje: <strong>el objetivo del feedback es que sea barato y temprano</strong>. Si solo te enteras de un fallo cuando la CI se pone roja tras 10 minutos, has perdido. <code>moodle-plugin-ci</code> (y su equivalente en cualquier stack) trae la CI a tu terminal.</p>\n<p>Ejemplo real: mod_exelearning corre esto en una <strong>matriz</strong> de PHP 8.1–8.4 × Moodle 4.5→5.2 × PostgreSQL/MariaDB. Mucho, pero cada combinación es el mismo comando que puedes lanzar en local.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000086\",\"markdownTextarea\":\"Mensaje: **el objetivo del feedback es que sea barato y temprano**. Si solo te enteras de un fallo cuando la CI se pone roja tras 10 minutos, has perdido. `moodle-plugin-ci` (y su equivalente en cualquier stack) trae la CI a tu terminal.\\n\\nEjemplo real: mod_exelearning corre esto en una **matriz** de PHP 8.1–8.4 × Moodle 4.5→5.2 × PostgreSQL/MariaDB. Mucho, pero cada combinación es el mismo comando que puedes lanzar en local.\",\"markdownTextareaHtml\":\"<p>Mensaje: <strong>el objetivo del feedback es que sea barato y temprano</strong>. Si solo te enteras de un fallo cuando la CI se pone roja tras 10 minutos, has perdido. <code>moodle-plugin-ci</code> (y su equivalente en cualquier stack) trae la CI a tu terminal.</p>\\n<p>Ejemplo real: mod_exelearning corre esto en una <strong>matriz</strong> de PHP 8.1–8.4 × Moodle 4.5→5.2 × PostgreSQL/MariaDB. Mucho, pero cada combinación es el mismo comando que puedes lanzar en local.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000087":{"name":"Lint y coding standards","isIndex":false,"fileName":"lint-y-coding-standards.html","fileUrl":"html/lint-y-coding-standards.html","prePageId":"SP00000082","nextPageId":"SP00000092","blocks":{"SP00000088":{"name":"El estilo, automatizado y no negociable","order":1,"idevices":{"SP00000089":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Discutir estilo en cada PR es tiempo perdido: que lo decida una herramienta.</p>\n<pre><code class=\"language-bash\">biome check .                   # JS/TS: lint + formato (Rust, rapidísimo)\nmago lint && mago fmt           # PHP: análisis y formato\nphpcs --standard=moodle local/x # PHP: estándar de Moodle\nwp plugin check my-plugin       # WordPress: sugerencias antes de publicar\n</code></pre>\n<p>Meta: <strong>0 warnings</strong>. El linter es un miembro más del equipo que nunca se cansa ni se despista.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000089\",\"markdownTextarea\":\"Discutir estilo en cada PR es tiempo perdido: que lo decida una herramienta.\\n\\n```bash\\nbiome check .                   # JS/TS: lint + formato (Rust, rapidísimo)\\nmago lint && mago fmt           # PHP: análisis y formato\\nphpcs --standard=moodle local/x # PHP: estándar de Moodle\\nwp plugin check my-plugin       # WordPress: sugerencias antes de publicar\\n```\\n\\nMeta: **0 warnings**. El linter es un miembro más del equipo que nunca se cansa ni se despista.\",\"markdownTextareaHtml\":\"<p>Discutir estilo en cada PR es tiempo perdido: que lo decida una herramienta.</p>\\n<pre><code class=\\\"language-bash\\\">biome check .                   # JS/TS: lint + formato (Rust, rapidísimo)\\nmago lint &amp;&amp; mago fmt           # PHP: análisis y formato\\nphpcs --standard=moodle local/x # PHP: estándar de Moodle\\nwp plugin check my-plugin       # WordPress: sugerencias antes de publicar\\n</code></pre>\\n<p>Meta: <strong>0 warnings</strong>. El linter es un miembro más del equipo que nunca se cansa ni se despista.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000090":{"name":"Notas del ponente","order":2,"idevices":{"SP00000091":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Cada plataforma, su estándar:<br>\n- <strong>biome</strong> para JS/TS: reemplaza ESLint+Prettier, es de Rust y vuela.<br>\n- <strong>mago</strong> para PHP: toolchain moderno (formatea y analiza).<br>\n- <strong>phpcs</strong> con <code>--standard=moodle</code> o WordPress (WPCS): el estándar oficial de cada ecosistema.<br>\n- <strong>WordPress Plugin Check</strong>: además del lint, te da <strong>sugerencias</strong> para pasar la revisión del directorio de plugins.</p>\n<p>Punto clave: esto corre <strong>antes</strong> en un hook de pre-commit, y <strong>otra vez</strong> en la CI como red de seguridad. Mismo comando en ambos sitios.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000091\",\"markdownTextarea\":\"Cada plataforma, su estándar:\\n- **biome** para JS/TS: reemplaza ESLint+Prettier, es de Rust y vuela.\\n- **mago** para PHP: toolchain moderno (formatea y analiza).\\n- **phpcs** con `--standard=moodle` o WordPress (WPCS): el estándar oficial de cada ecosistema.\\n- **WordPress Plugin Check**: además del lint, te da **sugerencias** para pasar la revisión del directorio de plugins.\\n\\nPunto clave: esto corre **antes** en un hook de pre-commit, y **otra vez** en la CI como red de seguridad. Mismo comando en ambos sitios.\",\"markdownTextareaHtml\":\"<p>Cada plataforma, su estándar:<br>\\n- <strong>biome</strong> para JS/TS: reemplaza ESLint+Prettier, es de Rust y vuela.<br>\\n- <strong>mago</strong> para PHP: toolchain moderno (formatea y analiza).<br>\\n- <strong>phpcs</strong> con <code>--standard=moodle</code> o WordPress (WPCS): el estándar oficial de cada ecosistema.<br>\\n- <strong>WordPress Plugin Check</strong>: además del lint, te da <strong>sugerencias</strong> para pasar la revisión del directorio de plugins.</p>\\n<p>Punto clave: esto corre <strong>antes</strong> en un hook de pre-commit, y <strong>otra vez</strong> en la CI como red de seguridad. Mismo comando en ambos sitios.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000092":{"name":"Dependabot y optimización","isIndex":false,"fileName":"dependabot-y-optimizacion.html","fileUrl":"html/dependabot-y-optimizacion.html","prePageId":"SP00000087","nextPageId":"SP00000099","blocks":{"SP00000093":{"name":"Actualizaciones automáticas: adiós al dependency hell","order":1,"idevices":{"SP00000094":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><ul>\n<li><strong>Dependabot</strong> abre <strong>PRs de actualización</strong> de dependencias automáticamente. Actualizas poco y a menudo en vez de un salto gigante y doloroso.</li>\n<li>Con la CI en verde, revisar y mergear cada bump es trivial. <em>(Este mismo repo lo usa: sus últimos commits son merges de dependabot.)</em></li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000094\",\"markdownTextarea\":\"- **Dependabot** abre **PRs de actualización** de dependencias automáticamente. Actualizas poco y a menudo en vez de un salto gigante y doloroso.\\n- Con la CI en verde, revisar y mergear cada bump es trivial. *(Este mismo repo lo usa: sus últimos commits son merges de dependabot.)*\",\"markdownTextareaHtml\":\"<ul>\\n<li><strong>Dependabot</strong> abre <strong>PRs de actualización</strong> de dependencias automáticamente. Actualizas poco y a menudo en vez de un salto gigante y doloroso.</li>\\n<li>Con la CI en verde, revisar y mergear cada bump es trivial. <em>(Este mismo repo lo usa: sus últimos commits son merges de dependabot.)</em></li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000095":{"name":"Paralelizar y optimizar","order":2,"idevices":{"SP00000096":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><ul>\n<li><strong>Matrices</strong> de jobs en paralelo (versiones, BBDD, SO) → resultados en minutos, no en horas.</li>\n<li><strong>Caché</strong> de dependencias y capas de Docker.</li>\n<li><strong>Despliegues por PR</strong> rápidos: cada pull request genera su <em>preview</em> para revisar el cambio antes de mergear.</li>\n</ul>\n<p>Menos espera = más iteraciones = mejor software.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000096\",\"markdownTextarea\":\"- **Matrices** de jobs en paralelo (versiones, BBDD, SO) → resultados en minutos, no en horas.\\n- **Caché** de dependencias y capas de Docker.\\n- **Despliegues por PR** rápidos: cada pull request genera su *preview* para revisar el cambio antes de mergear.\\n\\nMenos espera = más iteraciones = mejor software.\",\"markdownTextareaHtml\":\"<ul>\\n<li><strong>Matrices</strong> de jobs en paralelo (versiones, BBDD, SO) → resultados en minutos, no en horas.</li>\\n<li><strong>Caché</strong> de dependencias y capas de Docker.</li>\\n<li><strong>Despliegues por PR</strong> rápidos: cada pull request genera su <em>preview</em> para revisar el cambio antes de mergear.</li>\\n</ul>\\n<p>Menos espera = más iteraciones = mejor software.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000097":{"name":"Notas del ponente","order":3,"idevices":{"SP00000098":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Ejemplo de matriz real: la CI de mod_exelearning cruza PHP × Moodle × BBDD y corre todo en paralelo. Sin paralelizar sería inviable; con paralelización cabe en cada PR.</p>\n<p>Conecta Dependabot con la charla entera: es <strong>automatizar el mantenimiento</strong>. El coste de estar al día baja tanto que dejas de posponerlo. Y como todo pasa por la misma CI, una actualización rota se detecta sola.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000098\",\"markdownTextarea\":\"Ejemplo de matriz real: la CI de mod_exelearning cruza PHP × Moodle × BBDD y corre todo en paralelo. Sin paralelizar sería inviable; con paralelización cabe en cada PR.\\n\\nConecta Dependabot con la charla entera: es **automatizar el mantenimiento**. El coste de estar al día baja tanto que dejas de posponerlo. Y como todo pasa por la misma CI, una actualización rota se detecta sola.\",\"markdownTextareaHtml\":\"<p>Ejemplo de matriz real: la CI de mod_exelearning cruza PHP × Moodle × BBDD y corre todo en paralelo. Sin paralelizar sería inviable; con paralelización cabe en cada PR.</p>\\n<p>Conecta Dependabot con la charla entera: es <strong>automatizar el mantenimiento</strong>. El coste de estar al día baja tanto que dejas de posponerlo. Y como todo pasa por la misma CI, una actualización rota se detecta sola.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000099":{"name":"La palabra clave: automatizar","isIndex":false,"fileName":"la-palabra-clave-automatizar.html","fileUrl":"html/la-palabra-clave-automatizar.html","prePageId":"SP00000092","nextPageId":"SP00000104","blocks":{"SP00000100":{"name":"Del portátil al deploy, una sola cinta","order":1,"idevices":{"SP00000101":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Todo lo de hoy es una idea repetida en capas: <strong>automatizar el feedback</strong>.</p>\n<pre><code class=\"language-text\">Make (local)  →  GitHub Actions (CI)  →  Pages / pre-release (deploy)\n</code></pre>\n<ul>\n<li>El mismo comando en tu máquina y en la nube.</li>\n<li><strong>Esta misma presentación</strong> se valida, se construye y se publica sola en cada push.</li>\n</ul>\n<blockquote>\n<p>Automatiza antes de escalar: lo que automatizas no se te olvida ni te lo saltas con prisas.</p>\n</blockquote></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000101\",\"markdownTextarea\":\"Todo lo de hoy es una idea repetida en capas: **automatizar el feedback**.\\n\\n```text\\nMake (local)  →  GitHub Actions (CI)  →  Pages / pre-release (deploy)\\n```\\n\\n- El mismo comando en tu máquina y en la nube.\\n- **Esta misma presentación** se valida, se construye y se publica sola en cada push.\\n\\n> Automatiza antes de escalar: lo que automatizas no se te olvida ni te lo saltas con prisas.\",\"markdownTextareaHtml\":\"<p>Todo lo de hoy es una idea repetida en capas: <strong>automatizar el feedback</strong>.</p>\\n<pre><code class=\\\"language-text\\\">Make (local)  →  GitHub Actions (CI)  →  Pages / pre-release (deploy)\\n</code></pre>\\n<ul>\\n<li>El mismo comando en tu máquina y en la nube.</li>\\n<li><strong>Esta misma presentación</strong> se valida, se construye y se publica sola en cada push.</li>\\n</ul>\\n<blockquote>\\n<p>Automatiza antes de escalar: lo que automatizas no se te olvida ni te lo saltas con prisas.</p>\\n</blockquote>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000102":{"name":"Notas del ponente","order":2,"idevices":{"SP00000103":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Cierre de la sección de CI y puente al final. Enseña, si puedes, el workflow de GitHub Actions de este repo y el sitio publicado en <code>erseco.github.io/talks</code> — el bucle completo, en vivo.</p>\n<p>Frase para rematar: <strong>\"la IA acelera el centro del proceso; la automatización protege los extremos\"</strong>. Ninguna sustituye al criterio; ambas lo amplifican.</p></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000103\",\"markdownTextarea\":\"Cierre de la sección de CI y puente al final. Enseña, si puedes, el workflow de GitHub Actions de este repo y el sitio publicado en `erseco.github.io/talks` — el bucle completo, en vivo.\\n\\nFrase para rematar: **\\\"la IA acelera el centro del proceso; la automatización protege los extremos\\\"**. Ninguna sustituye al criterio; ambas lo amplifican.\",\"markdownTextareaHtml\":\"<p>Cierre de la sección de CI y puente al final. Enseña, si puedes, el workflow de GitHub Actions de este repo y el sitio publicado en <code>erseco.github.io/talks</code> — el bucle completo, en vivo.</p>\\n<p>Frase para rematar: <strong>\\\"la IA acelera el centro del proceso; la automatización protege los extremos\\\"</strong>. Ninguna sustituye al criterio; ambas lo amplifican.</p>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}},"SP00000104":{"name":"Cierre","isIndex":false,"fileName":"cierre.html","fileUrl":"html/cierre.html","prePageId":"SP00000099","nextPageId":null,"blocks":{"SP00000105":{"name":"Takeaways","order":1,"idevices":{"SP00000106":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><ol>\n<li><strong>Automatiza tu entorno</strong>: shell, scripts propios, brew/make.</li>\n<li><strong>Dale a la IA herramientas (MCP) y contexto</strong> (skills, <code>CLAUDE.md</code>, ADRs).</li>\n<li><strong>Que la IA documente de forma trazable</strong>: ADRs y registro de quién/qué modelo decidió.</li>\n<li><strong>Tu Makefile local ES tu CI</strong>: el mismo comando en los dos sitios.</li>\n<li><strong>Alpine + Dependabot + paralelizar</strong>… y <strong>revisa siempre el diff</strong>.</li>\n</ol></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000106\",\"markdownTextarea\":\"1. **Automatiza tu entorno**: shell, scripts propios, brew/make.\\n2. **Dale a la IA herramientas (MCP) y contexto** (skills, `CLAUDE.md`, ADRs).\\n3. **Que la IA documente de forma trazable**: ADRs y registro de quién/qué modelo decidió.\\n4. **Tu Makefile local ES tu CI**: el mismo comando en los dos sitios.\\n5. **Alpine + Dependabot + paralelizar**… y **revisa siempre el diff**.\",\"markdownTextareaHtml\":\"<ol>\\n<li><strong>Automatiza tu entorno</strong>: shell, scripts propios, brew/make.</li>\\n<li><strong>Dale a la IA herramientas (MCP) y contexto</strong> (skills, <code>CLAUDE.md</code>, ADRs).</li>\\n<li><strong>Que la IA documente de forma trazable</strong>: ADRs y registro de quién/qué modelo decidió.</li>\\n<li><strong>Tu Makefile local ES tu CI</strong>: el mismo comando en los dos sitios.</li>\\n<li><strong>Alpine + Dependabot + paralelizar</strong>… y <strong>revisa siempre el diff</strong>.</li>\\n</ol>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}},"SP00000107":{"name":"Enlaces y gracias","order":2,"idevices":{"SP00000108":{"order":1,"htmlView":"<div class=\"exe-markdown-template\"><div class=\"markdownTextIdeviceContent\"><div class=\"exe-markdown-activity\"><div class=\"markdown-body\"><p>Gracias. ¿Preguntas?</p>\n<ul>\n<li>Repositorio de la charla — <a href=\"https://github.com/erseco/talks\">https://github.com/erseco/talks</a></li>\n<li>Web de presentaciones — <a href=\"https://erseco.github.io/talks/\">https://erseco.github.io/talks/</a></li>\n<li>mod_exelearning — <a href=\"https://github.com/exelearning/mod_exelearning\">https://github.com/exelearning/mod_exelearning</a></li>\n<li>alpine-moodle — <a href=\"https://github.com/erseco/alpine-moodle\">https://github.com/erseco/alpine-moodle</a></li>\n<li>GitHub de Ernesto — <a href=\"https://github.com/erseco\">https://github.com/erseco</a></li>\n<li>Web personal — <a href=\"https://ernesto.es\">https://ernesto.es</a></li>\n<li>Mis instrucciones personalizadas — <TODO: enlace></li>\n</ul></div></div></div></div>","jsonProperties":"{\"ideviceId\":\"SP00000108\",\"markdownTextarea\":\"Gracias. ¿Preguntas?\\n\\n- Repositorio de la charla — <https://github.com/erseco/talks>\\n- Web de presentaciones — <https://erseco.github.io/talks/>\\n- mod_exelearning — <https://github.com/exelearning/mod_exelearning>\\n- alpine-moodle — <https://github.com/erseco/alpine-moodle>\\n- GitHub de Ernesto — <https://github.com/erseco>\\n- Web personal — <https://ernesto.es>\\n- Mis instrucciones personalizadas — <TODO: enlace>\",\"markdownTextareaHtml\":\"<p>Gracias. ¿Preguntas?</p>\\n<ul>\\n<li>Repositorio de la charla — <a href=\\\"https://github.com/erseco/talks\\\">https://github.com/erseco/talks</a></li>\\n<li>Web de presentaciones — <a href=\\\"https://erseco.github.io/talks/\\\">https://erseco.github.io/talks/</a></li>\\n<li>mod_exelearning — <a href=\\\"https://github.com/exelearning/mod_exelearning\\\">https://github.com/exelearning/mod_exelearning</a></li>\\n<li>alpine-moodle — <a href=\\\"https://github.com/erseco/alpine-moodle\\\">https://github.com/erseco/alpine-moodle</a></li>\\n<li>GitHub de Ernesto — <a href=\\\"https://github.com/erseco\\\">https://github.com/erseco</a></li>\\n<li>Web personal — <a href=\\\"https://ernesto.es\\\">https://ernesto.es</a></li>\\n<li>Mis instrucciones personalizadas — <TODO: enlace></li>\\n</ul>\",\"markdownInfoDurationInput\":\"\",\"markdownInfoDurationTextInput\":\"Duración:\",\"markdownInfoParticipantsInput\":\"\",\"markdownInfoParticipantsTextInput\":\"Agrupar:\",\"markdownFeedbackInput\":\"Mostrar comentarios\",\"markdownFeedbackTextarea\":\"\",\"markdownFeedbackTextareaHtml\":\"\"}"}}}}}};